"use client"

import { useEffect, useState } from 'react'

export default function OpenWrtPage() {
  const [data, setData] = useState<any>(null)
  const [error, setError] = useState('')

  useEffect(() => {
    fetch('/api/admin/openwrt/nodes', { credentials: 'include' })
      .then(async (res) => {
        if (!res.ok) throw new Error('加载失败')
        return res.json()
      })
      .then(setData)
      .catch(() => setError('暂时无法获取 OpenWrt 列表，请确认以 root 登录后访问。'))
  }, [])

  return (
    <div>
      <div className="header-row"><h2>OpenWrt 监控</h2></div>
      <div className="table-wrap">
        {error ? <div>{error}</div> : !data ? <div>加载中…</div> : (
          <table>
            <thead><tr><th>节点 ID</th><th>名称</th><th>内网 IP</th><th>外网 IP</th><th>CPU 负载</th><th>在线设备数</th><th>状态</th></tr></thead>
            <tbody>
              {data.items.map((n: any) => (
                <tr key={n.device_id}><td>{n.device_id}</td><td>{n.name || '-'}</td><td>{n.inner_ip || '-'}</td><td>{n.outer_ip || '-'}</td><td>{n.cpu_load ?? '-'}</td><td>{n.devices ?? '-'}</td><td><span className={`badge ${n.status}`}>{n.status}</span></td></tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  )
}
